import React from "react";
import { useNavigate } from "react-router-dom";
import { FaUserCircle, FaRegBell, FaCalendarAlt, FaUpload, FaHistory } from "react-icons/fa";
import styles from "./userdashboard.module.css"; // Import the CSS module

const UserDashBoard = () => {
  const navigate = useNavigate();
  const userEmail = localStorage.getItem("userEmail");

  return (
    <div className={styles.container}>
      {/* Vertical Sidebar */}
      <div className={styles.sidebar}>
        <img src="/assets/ODCSE Logo.png" alt="Logo" className={styles.logo} />
        <ul className={styles.navList}>
          <li className={styles.smallText} onClick={() => navigate("/events")}> <FaCalendarAlt className={styles.navIcon} /> Events </li>
          <li className={styles.smallText} onClick={() => navigate("/upload-events")}> <FaUpload className={styles.navIcon} /> Upload Events </li>
          <li className={styles.smallText} onClick={() => navigate("/history")}> <FaHistory className={styles.navIcon} /> History </li>
        </ul>
      </div>
      {/* Main Content */}
      <div className={styles.mainContent}>
        <div className={styles.header}>
          <div className={styles.iconContainer}>
            <FaRegBell className={styles.bellIcon} onClick={() => navigate("/notifications")} />
            <FaUserCircle className={styles.userIcon} onClick={() => navigate(`/profile?email=${userEmail}`)} />
          </div>
        </div>
        <h1 className={styles.title}>Welcome to User Dashboard</h1>
      </div>
    </div>
  );
};

export default UserDashBoard;
